import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../api/axios';
import Navigation from '../components/Navigation';

const Dashboard = () => {
  const navigate = useNavigate();
  const [stats, setStats] = useState({
    total: 0,
    pending: 0,
    closed: 0,
  });
  const [userRole, setUserRole] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const role = localStorage.getItem('role');
    setUserRole(role);
    fetchStats();
  }, []);

  const fetchStats = async () => {
    try {
      const { data } = await API.get('/complaints/stats');
      setStats({
        total: data.total || 0,
        pending: data.pending || 0,
        assigned: data.assigned || 0,
        inProgress: data.inProgress || 0,
        onHold: data.onHold || 0,
        closed: data.closed || 0
      });
    } catch (err) {
      console.error('Error fetching stats:', err);
    } finally {
      setLoading(false);
    }
  };

  const handleNavigate = (path) => navigate(path);

  const isSuperAdmin = userRole === 'SuperAdmin';
  const isUser = userRole === 'User';
  const isStaff = ['Networking Staff', 'Plumber', 'Electrician', 'Software Developer'].includes(userRole);

  return (
    <div style={styles.pageWrapper}>
      <Navigation />

      <div style={styles.contentArea}>
        {/* Header Section */}
        <div style={styles.headerSection}>
          <div>
            <h1 style={styles.mainTitle}>Dashboard</h1>
            <p style={styles.subtitle}>Welcome to your Ticket Management System</p>
          </div>
        </div>

        {/* Statistics Cards */}
        {!loading && (
          <div style={styles.section}>
            <h2 style={styles.sectionTitle}>📊 Complaint Statistics</h2>
            <div style={styles.statsGrid}>
              {isUser ? (
                <>
                  <StatCard icon="📋" label="Total Complaints" value={stats.total} color="#38bdf8" />
                  <StatCard icon="⏱️" label="Pending" value={stats.pending} color="#f59e0b" />
                  <StatCard icon="✅" label="Completed" value={stats.closed} color="#10b981" />
                </>
              ) : (
                <>
                  <StatCard icon="📋" label="Total Tickets" value={stats.total} color="#38bdf8" />
                  <StatCard icon="⏱️" label="Pending" value={stats.pending} color="#f59e0b" />
                  <StatCard icon="👤" label="Assigned" value={stats.assigned} color="#8b5cf6" />
                  <StatCard icon="⚙️" label="In Progress" value={stats.inProgress} color="#3b82f6" />
                  <StatCard icon="🔒" label="On Hold" value={stats.onHold} color="#ef4444" />
                  <StatCard icon="✅" label="Completed" value={stats.closed} color="#10b981" />
                </>
              )}
            </div>
          </div>
        )}

        {/* Admin Controls Section */}
        {isSuperAdmin && (
          <div style={styles.section}>
            <div style={styles.sectionHeader}>
              <span style={styles.sectionIcon}>🔐</span> <h2 style={styles.sectionTitle}>Admin Controls</h2>
            </div>
            <div style={styles.buttonsGrid}>
              <NavButton icon="🏢" label="Department Master" onClick={() => handleNavigate('/department')} />
              <NavButton icon="📚" label="Programme Master" onClick={() => handleNavigate('/programme')} />
              <NavButton icon="🏠" label="Block Master" onClick={() => handleNavigate('/block')} />
              <NavButton icon="🚪" label="Room Master" onClick={() => handleNavigate('/room')} />
              <NavButton icon="👑" label="Role Master" onClick={() => handleNavigate('/role')} />
              <NavButton icon="👥" label="User Management" onClick={() => handleNavigate('/users')} />
            </div>
          </div>
        )}

        {/* Ticket Management */}
        <div style={styles.section}>
          <h2 style={styles.sectionTitle}>🎫 Ticket Management</h2>
          <div style={styles.buttonsGrid}>
            {/* Raise Complaint - Available to User and SuperAdmin */}
            {(isUser || isSuperAdmin) && (
              <NavButton icon="📝" label="Raise New Ticket" onClick={() => handleNavigate('/raise-complaint')} primary />
            )}

            {/* View All Tickets - SuperAdmin, Staff, and User (Logic filters inside ComplaintsList) */}
            <NavButton icon="📋" label={isSuperAdmin ? "View All Tickets" : "View My Tickets"} onClick={() => handleNavigate('/complaints')} />

            {/* Generate Report - Only for SuperAdmin */}
            {isSuperAdmin && (
              <NavButton icon="📈" label="Generate Report" onClick={() => handleNavigate('/report')} primary />
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ icon, label, value, color }) => (
  <div style={{ ...styles.statCard, borderTopColor: color }}>
    <div style={styles.statIcon}>{icon}</div>
    <div style={styles.statLabel}>{label}</div>
    <div style={{ ...styles.statValue, color: color }}>{value}</div>
  </div>
);

const NavButton = ({ icon, label, onClick, primary = false }) => (
  <button
    onClick={onClick}
    style={primary ? { ...styles.btnPrimary } : { ...styles.btnSecondary }}
    onMouseEnter={e => {
      e.currentTarget.style.transform = 'translateY(-5px)';
      e.currentTarget.style.boxShadow = primary
        ? '0 20px 50px -10px rgba(56, 189, 248, 0.4)'
        : '0 20px 50px -10px rgba(255, 255, 255, 0.1)';
    }}
    onMouseLeave={e => {
      e.currentTarget.style.transform = 'translateY(0)';
      e.currentTarget.style.boxShadow = primary
        ? '0 10px 30px -8px rgba(56, 189, 248, 0.3)'
        : '0 10px 30px -8px rgba(0, 0, 0, 0.2)';
    }}
  >
    <span style={styles.btnIcon}>{icon}</span>
    <span>{label}</span>
  </button>
);

const styles = {
  pageWrapper: {
    minHeight: '100vh',
    background: 'linear-gradient(135deg, #0f172a 0%, #1a1f35 50%, #0f172a 100%)',
    color: '#e0e7ff',
    fontFamily: "'Poppins', sans-serif",
  },
  contentArea: {
    maxWidth: '1400px',
    margin: '0 auto',
    padding: '40px 30px',
  },
  headerSection: {
    marginBottom: '50px',
  },
  mainTitle: {
    fontSize: '2.5rem',
    fontWeight: 800,
    background: 'linear-gradient(135deg, #38bdf8, #818cf8)',
    WebkitBackgroundClip: 'text',
    WebkitTextFillColor: 'transparent',
    backgroundClip: 'text',
    marginBottom: '10px',
  },
  subtitle: {
    fontSize: '1.1rem',
    color: '#94a3b8',
    fontWeight: 500,
  },
  section: {
    marginBottom: '50px',
  },
  sectionTitle: {
    fontSize: '1.5rem',
    fontWeight: 700,
    color: '#e0e7ff',
    marginBottom: '25px',
    letterSpacing: '-0.5px',
  },
  statsGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fit, minmax(160px, 1fr))',
    gap: '20px',
  },
  statCard: {
    background: 'linear-gradient(135deg, rgba(30, 41, 59, 0.5), rgba(30, 41, 59, 0.2))',
    backdropFilter: 'blur(15px)',
    border: '2px solid rgba(51, 65, 85, 0.3)',
    borderTopWidth: '4px',
    borderRadius: '16px',
    padding: '28px 20px',
    textAlign: 'center',
    transition: 'all 0.3s ease',
    cursor: 'pointer',
  },
  statIcon: {
    fontSize: '2rem',
    marginBottom: '12px',
  },
  statLabel: {
    fontSize: '0.85rem',
    color: '#94a3b8',
    fontWeight: 600,
    marginBottom: '12px',
    textTransform: 'uppercase',
    letterSpacing: '0.5px',
  },
  statValue: {
    fontSize: '2.2rem',
    fontWeight: 800,
  },
  buttonsGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))',
    gap: '18px',
  },
  btnPrimary: {
    padding: '18px 24px',
    background: 'linear-gradient(135deg, #38bdf8, #818cf8)',
    color: 'white',
    border: 'none',
    borderRadius: '14px',
    fontWeight: 700,
    fontSize: '0.95rem',
    cursor: 'pointer',
    transition: 'all 0.3s ease',
    fontFamily: "'Poppins', sans-serif",
    boxShadow: '0 10px 30px -8px rgba(56, 189, 248, 0.3)',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    gap: '10px',
    textTransform: 'uppercase',
    letterSpacing: '0.5px',
  },
  btnSecondary: {
    padding: '18px 24px',
    background: 'rgba(30, 41, 59, 0.5)',
    color: '#e0e7ff',
    border: '2px solid rgba(51, 65, 85, 0.4)',
    borderRadius: '14px',
    fontWeight: 700,
    fontSize: '0.95rem',
    cursor: 'pointer',
    transition: 'all 0.3s ease',
    fontFamily: "'Poppins', sans-serif",
    boxShadow: '0 10px 30px -8px rgba(0, 0, 0, 0.2)',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    gap: '10px',
    textTransform: 'uppercase',
    letterSpacing: '0.5px',
  },
  btnIcon: {
    fontSize: '1.2rem',
  },
};

export default Dashboard;
